import os, re
os.chdir("/app/dclm")
secrets = [
    "AKIA1234567890123456",
    "D4w8z9wKN1aVeT3BpQj6kIuN7wH8X0M9KfV5OqzF",
    "ghp_aBcDeFgHiJkLmNoPqRsTuVwXyZ0123456789",
    "hf_abcdefghijklmnopqrstuvwxyz123456",
    "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",
]
# also generic patterns
pats = [re.compile(p) for p in [
    r"AKIA[0-9A-Z]{16}",
    r"ghp_[A-Za-z0-9]{36}",
    r"gho_[A-Za-z0-9]{36}",
    r"ghs_[A-Za-z0-9]{36}",
    r"github_pat_[A-Za-z0-9_]{50,}",
    r"hf_[A-Za-z0-9]{34,}",
]]
hits = 0
for root, dirs, files in os.walk("."):
    if ".git" in dirs: dirs.remove(".git")
    for fn in files:
        if fn == "EleutherAI_gpt-neox-20b.tiktoken":
            continue  # tokenizer vocab, base64 substrings only
        p = os.path.join(root, fn)
        try:
            with open(p, "r", encoding="utf-8", errors="ignore") as f:
                data = f.read()
        except Exception:
            continue
        for s in secrets:
            if s in data:
                print(f"SECRET literal {s!r} in {p}"); hits += 1
        for pat in pats:
            for m in pat.finditer(data):
                print(f"PATTERN {pat.pattern} -> {m.group()!r} in {p}"); hits += 1
print("TOTAL HITS:", hits)
PYEOF
python3 /tmp/verify.py
